type AnyFunc = (...args: unknown[]) => unknown;

type Debounced<F extends AnyFunc> = {
  (...args: Parameters<F>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<F extends AnyFunc>(fn: F, delay: number): Debounced<F> {
  let timer: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<F> | null = null;

  function invoke() {
    if (pendingArgs !== null) {
      fn(...pendingArgs);
      pendingArgs = null;
    }
  }

  function clear() {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
  }

  const debounced = function (...args: Parameters<F>): void {
    pendingArgs = args;
    clear();
    timer = setTimeout(() => {
      timer = null;
      invoke();
    }, delay);
  } as Debounced<F>;

  debounced.cancel = function () {
    clear();
    pendingArgs = null;
  };

  debounced.flush = function () {
    clear();
    invoke();
  };

  return debounced;
}

