type CronField = {
  min: number;
  max: number;
};

const FIELD_RANGES: Record<string, CronField> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

export type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

function assertInRange(value: number, field: CronField, raw: string): void {
  if (value < field.min || value > field.max) {
    throw new RangeError(
      `Value ${value} out of range [${field.min}-${field.max}] in expression "${raw}"`
    );
  }
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = field;

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Step value: */step or range/step
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in segment "${segment}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map(Number);
        if (isNaN(lo) || isNaN(hi)) {
          throw new SyntaxError(`Invalid range in segment "${segment}"`);
        }
        assertInRange(lo, field, segment);
        assertInRange(hi, field, segment);
        if (lo > hi) {
          throw new RangeError(`Range start exceeds end in segment "${segment}"`);
        }
        rangeMin = lo;
        rangeMax = hi;
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start)) {
          throw new SyntaxError(`Invalid step base in segment "${segment}"`);
        }
        assertInRange(start, field, segment);
        rangeMin = start;
      }
    }

    const results: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      results.push(v);
    }
    return results;
  }

  // Range: lo-hi
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range in segment "${segment}"`);
    }
    const lo = parseInt(parts[0], 10);
    const hi = parseInt(parts[1], 10);
    if (isNaN(lo) || isNaN(hi)) {
      throw new SyntaxError(`Non-numeric range values in segment "${segment}"`);
    }
    assertInRange(lo, field, segment);
    assertInRange(hi, field, segment);
    if (lo > hi) {
      throw new RangeError(`Range start exceeds end in segment "${segment}"`);
    }
    return Array.from({ length: hi - lo + 1 }, (_, i) => lo + i);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const values = segment.split(",").map((s) => {
      const v = parseInt(s.trim(), 10);
      if (isNaN(v)) {
        throw new SyntaxError(`Non-numeric value "${s}" in list "${segment}"`);
      }
      assertInRange(v, field, segment);
      return v;
    });
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Unrecognized cron segment "${segment}"`);
  }
  assertInRange(value, field, segment);
  return [value];
}

function normalizeDayOfWeek(values: number[]): number[] {
  // Treat 7 as Sunday (0)
  const normalized = values.map((v) => (v === 7 ? 0 : v));
  return [...new Set(normalized)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${fields.length} in expression "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  const minute = parseSegment(minuteRaw, FIELD_RANGES.minute);
  const hour = parseSegment(hourRaw, FIELD_RANGES.hour);
  const dayOfMonth = parseSegment(domRaw, FIELD_RANGES.dayOfMonth);
  const month = parseSegment(monthRaw, FIELD_RANGES.month);
  const dayOfWeek = normalizeDayOfWeek(
    parseSegment(dowRaw, { min: 0, max: 7 })
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

