type CronField = {
  values: number[];
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof ParsedCron, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

function expandRange(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Wildcard
  if (segment === "*") return expandRange(min, max);

  // Step: */n or range/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    const [rangeMin, rangeMax] = base === "*"
      ? [min, max]
      : base.includes("-")
        ? parseRangeBounds(base, min, max)
        : (() => { const n = parseInt(base, 10); return [n, max] as [number, number]; })();

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) result.push(i);
    return result;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [lo, hi] = parseRangeBounds(segment, min, max);
    return expandRange(lo, hi);
  }

  // Single number
  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new Error(`Invalid value: ${segment}`);
  if (val < min || val > max) throw new Error(`Value ${val} out of range [${min},${max}]`);
  return [val];
}

function parseRangeBounds(segment: string, min: number, max: number): [number, number] {
  const [loStr, hiStr] = segment.split("-");
  const lo = parseInt(loStr, 10);
  const hi = parseInt(hiStr, 10);
  if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range: ${segment}`);
  if (lo < min || hi > max || lo > hi) throw new Error(`Range ${segment} out of bounds [${min},${max}]`);
  return [lo, hi];
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma list
  const parts = field.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max)) values.add(v);
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const keys = Object.keys(FIELD_RANGES) as (keyof ParsedCron)[];
  const result = {} as ParsedCron;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(fields[i], min, max);
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function assertInRange(value: number, field: CronField): void {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range for field "${field}" (expected ${min}–${max})`
    );
  }
}

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function parseField(token: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list — recurse on each part
  if (token.includes(",")) {
    const values = token
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step: */step or start-end/step
  if (token.includes("/")) {
    const [rangePart, stepPart] = token.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${token}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((n) => parseInt(n, 10));
      if (isNaN(s) || isNaN(e)) throw new SyntaxError(`Invalid range in "${token}"`);
      assertInRange(s, field);
      assertInRange(e, field);
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new SyntaxError(`Invalid step expression "${token}"`);
      assertInRange(start, field);
      end = max;
    }

    const result: number[] = [];
    for (let v = start; v <= end; v += step) result.push(v);
    return result;
  }

  // Range: start-end
  if (token.includes("-")) {
    const [s, e] = token.split("-").map((n) => parseInt(n, 10));
    if (isNaN(s) || isNaN(e)) throw new SyntaxError(`Invalid range "${token}"`);
    assertInRange(s, field);
    assertInRange(e, field);
    return range(s, e);
  }

  // Wildcard
  if (token === "*") {
    return range(min, max);
  }

  // Single number
  const num = parseInt(token, 10);
  if (isNaN(num)) throw new SyntaxError(`Unrecognised token "${token}" for field "${field}"`);
  assertInRange(num, field);
  return [num];
}

function normaliseDayOfWeek(values: number[]): number[] {
  // Map Sunday=7 to Sunday=0 (both representations are valid)
  const normalised = values.map((v) => (v === 7 ? 0 : v));
  return [...new Set(normalised)].sort((a, b) => a - b);
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields but got ${fields.length} in expression "${expression}"`
    );
  }

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = fields;

  const dayOfWeekRaw = parseField(dowToken, "dayOfWeek");

  return {
    minute: parseField(minuteToken, "minute"),
    hour: parseField(hourToken, "hour"),
    dayOfMonth: parseField(domToken, "dayOfMonth"),
    month: parseField(monthToken, "month"),
    dayOfWeek: normaliseDayOfWeek(dayOfWeekRaw),
  };
}

