}

function parseSegment(seg: string, field: CronField): number[] {
  const { min, max } = field;

  // step: */n or a-b/n
  if (seg.includes("/")) {
    const [rangePart, stepStr] = seg.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${stepStr}`);
    let start = min;
    let end = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = clamp(s, min, max);
        end   = clamp(e, min, max);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // wildcard
  if (seg === "*") {
    const result: number[] = [];
    for (let i = min; i <= max; i++) result.push(i);
    return result;
  }

  // range: a-b
  if (seg.includes("-")) {
    const [s, e] = seg.split("-").map(Number);
    const start = clamp(s, min, max);
    const end   = clamp(e, min, max);
    if (start > end) throw new RangeError(`Range start ${start} > end ${end}`);
    const result: number[] = [];
    for (let i = start; i <= end; i++) result.push(i);
    return result;
  }

  // number
  const n = parseInt(seg, 10);
  if (isNaN(n)) throw new Error(`Invalid value: ${seg}`);
  return [clamp(n, min, max)];
}

function parseField(expr: string, field: CronField): number[] {
  const parts = expr.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), field)) values.add(v);
  }
  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute:     parseField(minuteExpr, FIELDS.minute),
    hour:       parseField(hourExpr,   FIELDS.hour),
    dayOfMonth: parseField(domExpr,    FIELDS.dayOfMonth),
    month:      parseField(monthExpr,  FIELDS.month),
    dayOfWeek:  parseField(dowExpr,    FIELDS.dayOfWeek),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

