const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function clamp(val: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, val));
}

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // comma-separated list — recurse on each part
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // wildcard
  if (expr === "*") return range(min, max);

  // step: */N or start-end/N
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0)
      throw new Error(`Invalid step in field "${field}": ${expr}`);

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = clamp(s, min, max);
        end = clamp(e, min, max);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end))
      throw new Error(`Invalid range in field "${field}": ${expr}`);
    if (start > end)
      throw new Error(`Range start > end in field "${field}": ${expr}`);
    if (start < min || end > max)
      throw new Error(
        `Range out of bounds in field "${field}": ${expr} (valid: ${min}-${max})`
      );
    return range(start, end);
  }

  // single number
  const val = parseInt(expr, 10);
  if (isNaN(val))
    throw new Error(`Invalid value in field "${field}": ${expr}`);
  if (val < min || val > max)
    throw new Error(
      `Value out of range in field "${field}": ${val} (valid: ${min}-${max})`
    );
  return [val];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  const dayOfWeekRaw = parseField(dowExpr, "dayOfWeek");
  // normalize: 7 (Sunday alt) → 0
  const dayOfWeek = [
    ...new Set(dayOfWeekRaw.map((v) => (v === 7 ? 0 : v))),
  ].sort((a, b) => a - b);

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek,
  };
}

