type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends AnyFunction>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  const cancel = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
      pendingArgs = undefined;
    }
  };

  const flush = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
      const args = pendingArgs as Parameters<T>;
      pendingArgs = undefined;
      fn(...args);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const invokeArgs = pendingArgs as Parameters<T>;
      pendingArgs = undefined;
      fn(...invokeArgs);
    }, delay);
  };

  debounced.cancel = cancel;
  debounced.flush = flush;

  return debounced;
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const argsToCall = pendingArgs;
      pendingArgs = undefined;
      if (argsToCall !== undefined) {
        fn(...argsToCall);
      }
    }, delay);
  };

  debounced.cancel = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  };

  debounced.flush = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
      const argsToCall = pendingArgs;
      pendingArgs = undefined;
      if (argsToCall !== undefined) {
        fn(...argsToCall);
      }
    }
  };

  return debounced;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      Object.keys(val).length > 0
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else {
      result[fullKey] = val as Primitive;
    }
  }
  return result;
}

export default flattenObject;

type CronField = {
  min: number;
  max: number;
};

const FIELDS: Record<string, CronField> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

export type CronResult = {
  minute:     number[];
  hour:       number[];
  dayOfMonth: number[];
  month:      number[];
  dayOfWeek:  number[];
};

function range(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) result.push(i);
  return result;
}

function clamp(val: number, min: number, max: number): number {
  if (val < min || val > max) throw new RangeError(`Value ${val} out of range [${min},${max}]`);
  return val;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = field;

  // Wildcard
  if (segment === "*") return range(min, max);

  // Step: */N or X-Y/N
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${stepStr}`);

    if (left === "*") return range(min, max, step);

    if (left.includes("-")) {
      const [startStr, endStr] = left.split("-");
      const start = clamp(parseInt(startStr, 10), min, max);
      const end   = clamp(parseInt(endStr,   10), min, max);
      if (start > end) throw new RangeError(`Invalid range ${start}-${end}`);
      return range(start, end, step);
    }

    const start = clamp(parseInt(left, 10), min, max);
    return range(start, max, step);
  }

  // Range: X-Y
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end   = clamp(parseInt(endStr,   10), min, max);
    if (start > end) throw new RangeError(`Invalid range ${start}-${end}`);
    return range(start, end);
  }

  // Single number
  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new Error(`Invalid value: ${segment}`);
  return [clamp(val, min, max)];
}

function parseField(expr: string, field: CronField): number[] {
  const parts = expr.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), field)) values.add(v);
  }
  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute:     parseField(minuteExpr, FIELDS.minute),
    hour:       parseField(hourExpr,   FIELDS.hour),
    dayOfMonth: parseField(domExpr,    FIELDS.dayOfMonth),
    month:      parseField(monthExpr,  FIELDS.month),
    dayOfWeek:  parseField(dowExpr,    FIELDS.dayOfWeek),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

