type CronField = {
  min: number;
  max: number;
};

const FIELDS: Record<string, CronField> = {
  minute:     { min: 0, max: 59 },
  hour:       { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month:      { min: 1, max: 12 },
  dayOfWeek:  { min: 0, max: 6 },
};

export type CronResult = {
  minute:     number[];
  hour:       number[];
  dayOfMonth: number[];
  month:      number[];
  dayOfWeek:  number[];
};

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter(v => v >= min && v <= max);
}

function parseField(expr: string, field: CronField): number[] {
  const { min, max } = field;
  const all = Array.from({ length: max - min + 1 }, (_, i) => i + min);

  // comma list — recurse on each part, dedupe, sort
  if (expr.includes(",")) {
    const vals = new Set(
      expr.split(",").flatMap(part => parseField(part.trim(), field))
    );
    return [...vals].sort((a, b) => a - b);
  }

  // wildcard
  if (expr === "*") return all;

  // step: */N or start-end/N
  if (expr.includes("/")) {
    const [rangeExpr, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${expr}`);

    let base: number[];
    if (rangeExpr === "*") {
      base = all;
    } else if (rangeExpr.includes("-")) {
      base = parseField(rangeExpr, field);
    } else {
      const start = parseInt(rangeExpr, 10);
      if (isNaN(start)) throw new Error(`Invalid step base: ${expr}`);
      base = all.filter(v => v >= start);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end) || start > end)
      throw new Error(`Invalid range: ${expr}`);
    return clamp(
      Array.from({ length: end - start + 1 }, (_, i) => i + start),
      min, max
    );
  }

  // single number
  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new Error(`Invalid value: ${expr}`);
  if (n < min || n > max) throw new Error(`Value ${n} out of range [${min},${max}]`);
  return [n];
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fieldKeys = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;
  const exprs     = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as CronResult;
  for (let i = 0; i < fieldKeys.length; i++) {
    const key = fieldKeys[i];
    result[key] = parseField(exprs[i], FIELDS[key]);
  }
  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map((v) => parseInt(v, 10));
        if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range in step: "${rangePart}"`);
        start = s;
        end = e;
      } else {
        start = parseInt(rangePart, 10);
        if (isNaN(start)) throw new Error(`Invalid start in step: "${rangePart}"`);
      }
    }

    if (start < min || end > max) {
      throw new Error(`Step range ${start}-${end} out of bounds [${min}, ${max}]`);
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: "${field}"`);
    }
    if (start > end) {
      throw new Error(`Range start ${start} is greater than end ${end}`);
    }
    if (start < min || end > max) {
      throw new Error(`Range ${start}-${end} out of bounds [${min}, ${max}]`);
    }

    return range(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: "${field}"`);
  }
  if (value < min || value > max) {
