  debounced.cancel = (): void => {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
    pendingArgs = null;
  };

  debounced.flush = (): void => {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
      const args = pendingArgs!;
      pendingArgs = null;
      fn(...args);
    }
  };

  return debounced;
