  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, min: number, max: number): number[] {
  const full = range(min, max);

  if (expr === "*") return full;

  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (expr.includes("/")) {
    const [rangeExpr, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value: "${stepStr}"`);

    const base = rangeExpr === "*" ? full : parseField(rangeExpr, min, max);
    const start = base[0];
    return base.filter((v) => (v - start) % step === 0);
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${expr}"`);
    if (start < min || end > max || start > end)
      throw new Error(`Range "${expr}" out of bounds [${min}-${max}]`);
    return range(start, end);
  }

  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid cron value: "${expr}"`);
  if (num < min || num > max)
    throw new Error(`Value ${num} out of bounds [${min}-${max}]`);
  return [num];
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim())
