type CronField = {
  values: number[];
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof ParsedCron, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function expandRange(min: number, max: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i += step) result.push(i);
  return result;
}

function parseField(expr: string, min: number, max: number): number[] {
  const allValues = () => expandRange(min, max);

  if (expr === "*") return allValues();

  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${expr}`);
    return expandRange(min, max, step);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${expr}`);
    const [rangeMin, rangeMax] = rangePart.includes("-")
      ? rangePart.split("-").map(Number)
      : [parseInt(rangePart, 10), max];
    validateBounds(rangeMin, rangeMax, min, max, expr);
    return expandRange(rangeMin, rangeMax, step);
  }

  if (expr.includes("-")) {
    const [start, end] = expr.split("-").map(Number);
    validateBounds(start, end, min, max, expr);
    if (start > end) throw new Error(`Invalid range: ${expr}`);
    return expandRange(start, end);
  }

  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid value: ${expr}`);
  if (num < min || num > max)
    throw new Error(`Value ${num} out of range [${min}-${max}]`);
  return [num];
}

function validateBounds(
  start: number,
  end: number,
  min: number,
  max: number,
  expr: string
): void {
  if (
    isNaN(start) ||
    isNaN(end) ||
    start < min ||
    start > max ||
    end < min ||
    end > max
  ) {
    throw new Error(`Value out of range [${min}-${max}]: ${expr}`);
  }
}

export default function parseCron(expression: string): ParsedCron {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new Error(`Expected 5 fields, got ${parts.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof ParsedCron)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as ParsedCron;
  for (let i = 0; i < fields.length; i++) {
    const field = fields[i];
    const [min, max] = FIELD_RANGES[field];
    result[field] = parseField(exprs[i], min, max);
  }
  return result;
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  function debounced(...args: Parameters<T>): void {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      const args = pendingArgs!;
      pendingArgs = undefined;
      fn(...args);
    }, delay);
  }

  debounced.cancel = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  };

  debounced.flush = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
      const args = pendingArgs!;
      pendingArgs = undefined;
      fn(...args);
    }
  };

  return debounced;
}

