    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${segment}`);
    if (start > end) throw new Error(`Range start > end: ${segment}`);
    return clamp(range(start, end), min, max);
  }

  // Single number
  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new Error(`Invalid value: ${segment}`);
  if (val < min || val > max) throw new Error(`Value ${val} out of range [${min},${max}]`);
  return [val];
}

function parseField(field: string, min: number, max: number): number[] {
  const parts = field.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max)) values.add(v);
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const fieldOrder: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];
  const fieldStrings = [minuteStr, hourStr, domStr, monthStr, dowStr];

  const result = {} as CronResult;
  for (let i = 0; i < 5; i++) {
    const name = fieldOrder[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(fieldStrings[i], min, max);
  }
  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(val: unknown): val is PlainObject {
  return (
    val !== null &&
    typeof val === "object" &&
    !Array.isArray(val) &&
    Object.getPrototypeOf(val) === Object.prototype
  );
}

export function deepMerge<T extends PlainObject>(target: T, source: Partial<T>): T {
  const output = { ...target } as PlainObject;

  for (const key of Object.keys(source) as Array<keyof T>) {
    const srcVal = source[key] as unknown;
    const tgtVal = output[key as string];

    if (isPlainObject(tgtVal) && isPlainObject(srcVal)) {
      output[key as string] = deepMerge(tgtVal, srcVal);
    } else if (Array.isArray(tgtVal) && Array.isArray(srcVal)) {
      output[key as string] = [...tgtVal, ...srcVal];
    } else if (srcVal !== undefined) {
      output[key as string] = srcVal;
    }
  }

  return output as T;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0 && prefix) {
    result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value)
        ? (value as unknown as Primitive)
        : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const range = (from: number, to: number): number[] =>
  Array.from({ length: to - from + 1 }, (_, i) => from + i);

const parseSegment = (segment: string, min: number, max: number): number[] => {
  // Wildcard
  if (segment === "*") return range(min, max);

  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);
    const baseValues = base === "*" ? range(min, max) : parseSegment(base, min, max);
    return baseValues.filter((v) => (v - baseValues[0]) % step === 0);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [fromStr, toStr] = segment.split("-");
    const from = parseInt(fromStr, 10);
    const to = parseInt(toStr, 10);
    if (isNaN(from) || isNaN(to)) throw new Error(`Invalid range: ${segment}`);
    if (from < min || to > max || from > to)
      throw new Error(`Range ${segment} out of bounds [${min}-${max}]`);
    return range(from, to);
  }

  // List: a,b,c
  if (segment.includes(",")) {
    return [
      ...new Set(
        segment
          .split(",")
          .flatMap((s) => parseSegment(s.trim(), min, max))
          .sort((a, b) => a - b)
      ),
    ];
  }

  // Single number
  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new Error(`Invalid value: ${segment}`);
  if (val < min || val > max)
    throw new Error(`Value ${val} out of bounds [${min}-${max}]`);
  return [val];
};

const parseCron = (expr: string): CronResult => {
  const fields = expr.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}`);

  const keys: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  return keys.reduce((acc, key, i) => {
    const [min, max] = FIELD_RANGES[key];
    acc[key] = parseSegment(fields[i], min, max);
    return acc;
  }, {} as CronResult);
};

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      Object.keys(val).length > 0
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else {
      result[fullKey] = Array.isArray(val) ? (JSON.stringify(val) as Primitive) : (val as Primitive);
    }
  }
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function expandRange(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function parseField(field: string, fieldName: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  const values = new Set<number>();

  for (const part of field.split(",")) {
    if (part === "*") {
      expandRange(min, max).forEach((v) => values.add(v));
      continue;
    }

    if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value in field "${fieldName}": ${part}`);
      }
      for (let i = min; i <= max; i += step) values.add(i);
      continue;
    }

    if (part.includes("/")) {
      const [rangePart, stepPart] = part.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value in field "${fieldName}": ${part}`);
      }
      let rangeMin = min;
      let rangeMax = max;
      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [lo, hi] = rangePart.split("-").map(Number);
          rangeMin = lo;
          rangeMax = hi;
        } else {
          rangeMin = parseInt(rangePart, 10);
        }
      }
      if (rangeMin < min || rangeMax > max || rangeMin > rangeMax) {
        throw new Error(`Range out of bounds in field "${fieldName}": ${part}`);
      }
      for (let i = rangeMin; i <= rangeMax; i += step) values.add(i);
      continue;
    }

    if (part.includes("-")) {
      const [lo, hi] = part.split("-").map(Number);
      if (isNaN(lo) || isNaN(hi)) {
        throw new Error(`Invalid range in field "${fieldName}": ${part}`);
      }
      if (lo < min || hi > max || lo > hi) {
        throw new Error(`Range out of bounds in field "${fieldName}": ${part}`);
      }
      expandRange(lo, hi).forEach((v) => values.add(v));
      continue;
    }

    const num = parseInt(part, 10);
    if (isNaN(num)) {
      throw new Error(`Invalid value in field "${fieldName}": ${part}`);
    }
    if (num < min || num > max) {
      throw new Error(
        `Value ${num} out of range [${min}, ${max}] for field "${fieldName}"`
      );
    }
    values.add(num);
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}`
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = parts;

  return {
    minute: parseField(minuteStr, "minute"),
    hour: parseField(hourStr, "hour"),
    dayOfMonth: parseField(dayOfMonthStr, "dayOfMonth"),
    month: parseField(monthStr, "month"),
    dayOfWeek: parseField(dayOfWeekStr, "dayOfWeek"),
  };
}

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timer: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => {
      timer = null;
      const args = pendingArgs!;
      pendingArgs = null;
      fn(...args);
    }, delay);
  } as DebouncedFunction<T>;

  debounced.cancel = function (): void {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
    pendingArgs = null;
  };

  debounced.flush = function (): void {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
      const args = pendingArgs!;
      pendingArgs = null;
      fn(...args);
    }
  };

  return debounced;
}

export interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronResult;

const FIELD_NAMES: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function buildRange(start: number, end: number, step = 1): number[] {
  if (start > end) throw new Error(`Invalid range: start ${start} > end ${end}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) result.push(i);
  return result;
}

function assertBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}-${max}] in "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  const stepIndex = segment.indexOf("/");

  if (stepIndex !== -1) {
    const rangeStr = segment.slice(0, stepIndex);
    const stepStr  = segment.slice(stepIndex + 1);
    const step     = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepStr}" in "${segment}"`);
    }

    let start: number;
    let end: number;

    if (rangeStr === "*") {
      start = min;
      end   = max;
    } else {
      const dashIndex = rangeStr.indexOf("-");
      if (dashIndex !== -1) {
        start = parseInt(rangeStr.slice(0, dashIndex), 10);
        end   = parseInt(rangeStr.slice(dashIndex + 1), 10);
      } else {
        start = parseInt(rangeStr, 10);
        end   = max;
      }

      if (isNaN(start) || isNaN(end)) {
        throw new Error(`Invalid range "${rangeStr}" in "${segment}"`);
      }

      assertBounds(start, min, max, segment);
      assertBounds(end,   min, max, segment);
    }

    return buildRange(start, end, step);
  }

  if (segment === "*") {
    return buildRange(min, max);
  }

  const dashIndex = segment.indexOf("-");
  if (dashIndex !== -1) {
    const start = parseInt(segment.slice(0, dashIndex), 10);
    const end   = parseInt(segment.slice(dashIndex + 1), 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range "${segment}"`);
    }

    assertBounds(start, min, max, segment);
    assertBounds(end,   min, max, segment);

    return buildRange(start, end);
  }

  const value = parseInt(segment, 10);

  if (isNaN(value)) {
    throw new Error(`Invalid value "${segment}"`);
  }

  assertBounds(value, min, max, segment);

  return [value];
}

function parseField(field: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const segment of field.split(",")) {
    const trimmed = segment.trim();

    if (trimmed === "") throw new Error(`Empty segment in field "${field}"`);

    for (const v of parseSegment(trimmed, min, max)) values.add(v);
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length} — "${expression}"`
    );
  }

  return Object.fromEntries(
    FIELD_NAMES.map((name, i) => {
      const { min, max } = FIELD_RANGES[name];
      return [name, parseField(fields[i], min, max)];
    })
  ) as CronResult;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function rangeArray(min: number, max: number, step = 1): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const result: number[] = [];
  for (let i = min; i <= max; i += step) {
    result.push(i);
  }
  return result;
}

function unique(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function validateValue(value: number, field: CronField): number {
  const { min, max } = FIELD_RANGES[field];
  // Normalize dayOfWeek: 7 is treated as 0 (Sunday)
  if (field === "dayOfWeek" && value === 7) return 0;
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of range [${min}, ${max}] for field "${field}"`
    );
  }
  return value;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard: *
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step: */n or range/n
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value "${stepStr}" in segment "${segment}"`);
    }

    let base: number[];
    if (left === "*") {
      base = rangeArray(min, max, step);
    } else if (left.includes("-")) {
      const [startStr, endStr] = left.split("-");
      const start = validateValue(parseInt(startStr, 10), field);
      const end = validateValue(parseInt(endStr, 10), field);
      if (start > end) {
        throw new Error(`Invalid range ${start}-${end} in segment "${segment}"`);
      }
      base = rangeArray(start, end, step);
    } else {
      const start = validateValue(parseInt(left, 10), field);
      base = rangeArray(start, max, step);
    }
    return base;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = validateValue(parseInt(startStr, 10), field);
    const end = validateValue(parseInt(endStr, 10), field);
    if (start > end) {
      throw new Error(`Invalid range ${start}-${end} in segment "${segment}"`);
    }
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${segment}" in field "${field}"`);
  }
  return [validateValue(value, field)];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  const values = segments.flatMap((segment) => parseSegment(segment.trim(), field));
  return unique(values);
}

export default function parseCron(expression: string): CronResult {
  const trimmed = expression.trim().replace(/\s+/g, " ");
  const parts = trimmed.split(" ");

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = parts;

  return {
    minute:     parseField(minuteExpr,     "minute"),
    hour:       parseField(hourExpr,       "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month:      parseField(monthExpr,      "month"),
    dayOfWeek:  parseField(dayOfWeekExpr,  "dayOfWeek"),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };
    for (const key of Object.keys(source)) {
      result[key] = deepMerge(target[key], source[key]);
    }
    return result;
  }

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  return source !== undefined ? source : target;
}

export default deepMerge;

const FIELD_RANGES = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

interface CronResult {
  minute:     number[];
  hour:       number[];
  dayOfMonth: number[];
  month:      number[];
  dayOfWeek:  number[];
}

function clamp(val: number, min: number, max: number): number {
  if (val < min || val > max) throw new RangeError(`Value ${val} out of range [${min}, ${max}]`);
  return val;
}

function range(from: number, to: number): number[] {
  const out: number[] = [];
  for (let i = from; i <= to; i++) out.push(i);
  return out;
}

function parseField(expr: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // comma list — recurse
  if (expr.includes(",")) {
    const parts = expr.split(",").flatMap(p => parseField(p.trim(), field));
    return [...new Set(parts)].sort((a, b) => a - b);
  }

  // wildcard
  if (expr === "*") return range(min, max);

  // step: */n or start-end/n
  if (expr.includes("/")) {
    const [left, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${stepStr}`);

    let from = min;
    let to   = max;

    if (left !== "*") {
      if (left.includes("-")) {
        const [a, b] = left.split("-").map(Number);
        from = clamp(a, min, max);
        to   = clamp(b, min, max);
        if (from > to) throw new RangeError(`Invalid range ${left}`);
      } else {
        from = clamp(parseInt(left, 10), min, max);
      }
    }

    const out: number[] = [];
    for (let i = from; i <= to; i += step) out.push(i);
    return out;
  }

  // range: a-b
  if (expr.includes("-")) {
    const [a, b] = expr.split("-").map(Number);
    const from = clamp(a, min, max);
    const to   = clamp(b, min, max);
    if (from > to) throw new RangeError(`Invalid range ${expr} for ${field}`);
    return range(from, to);
  }

  // single number
  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new Error(`Invalid token "${expr}" for ${field}`);
  return [clamp(n, min, max)];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(val: unknown): val is PlainObject {
  return (
    val !== null &&
    typeof val === "object" &&
    !Array.isArray(val) &&
    Object.getPrototypeOf(val) === Object.prototype
  );
}

export function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const srcVal = source[key];
    const tgtVal = result[key];

    if (Array.isArray(srcVal) && Array.isArray(tgtVal)) {
      result[key] = [...tgtVal, ...srcVal];
    } else if (isPlainObject(srcVal) && isPlainObject(tgtVal)) {
      result[key] = deepMerge(tgtVal, srcVal);
    } else {
      result[key] = srcVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timer: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  const debounced = function (...args: Parameters<T>): void {
    pendingArgs = args;
    if (timer !== undefined) clearTimeout(timer);
    timer = setTimeout(() => {
      timer = undefined;
      const args = pendingArgs!;
      pendingArgs = undefined;
      fn(...args);
    }, delay);
  } as DebouncedFunction<T>;

  debounced.cancel = (): void => {
    if (timer !== undefined) {
      clearTimeout(timer);
      timer = undefined;
    }
    pendingArgs = undefined;
  };

  debounced.flush = (): void => {
    if (timer !== undefined) {
      clearTimeout(timer);
      timer = undefined;
      const args = pendingArgs!;
      pendingArgs = undefined;
      fn(...args);
    }
  };

  return debounced;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      Object.keys(val).length > 0
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else {
      result[fullKey] = Array.isArray(val) ? JSON.stringify(val) : (val as Primitive);
    }
  }
  return result;
}

export default flattenObject;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const tokensNeeded = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
      const elapsed = Date.now() - this.lastRefillTime;
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs - elapsed);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };

    for (const key of Object.keys(source)) {
      result[key] = Object.prototype.hasOwnProperty.call(target, key)
        ? deepMerge(target[key], source[key])
        : source[key];
    }

    return result;
  }

  return source === undefined ? target : source;
}

export default deepMerge;

type DebouncedFunction<T extends (...args: unknown[]) => unknown> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: unknown[]) => unknown>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timer: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => {
      const a = pendingArgs!;
      timer = null;
      pendingArgs = null;
      fn(...a);
    }, delay);
  };

  debounced.cancel = (): void => {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
    pendingArgs = null;
  };

  debounced.flush = (): void => {
    if (timer === null || pendingArgs === null) return;
    clearTimeout(timer);
    const a = pendingArgs;
    timer = null;
    pendingArgs = null;
    fn(...a);
  };

  return debounced;
}

type CronField = {
  values: number[];
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof ParsedCron, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function clamp(val: number, min: number, max: number): number {
  if (val < min || val > max) throw new RangeError(`Value ${val} out of range [${min}, ${max}]`);
  return val;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${stepStr}`);
    const [start, end] =
      rangePart === "*" ? [min, max] : rangePart.split("-").map(Number);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in step: ${rangePart}`);
    clamp(start, min, max);
    clamp(end, min, max);
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new RangeError(`Range start ${start} > end ${end}`);
    return range(start, end);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Number
  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new Error(`Invalid value: ${segment}`);
  return [clamp(val, min, max)];
}

function parseField(field: string, min: number, max: number): number[] {
  const parts = field.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max)) values.add(v);
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof ParsedCron)[];

  return {
    minute: parseField(minuteStr, ...FIELD_RANGES.minute),
    hour: parseField(hourStr, ...FIELD_RANGES.hour),
    dayOfMonth: parseField(domStr, ...FIELD_RANGES.dayOfMonth),
    month: parseField(monthStr, ...FIELD_RANGES.month),
    dayOfWeek: parseField(dowStr, ...FIELD_RANGES.dayOfWeek),
  };
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };
    for (const key of Object.keys(source)) {
      result[key] = deepMerge(target[key], source[key]);
    }
    return result;
  }

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  return source !== undefined ? source : target;
}

export default deepMerge;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(
  expression: string,
  fieldName: keyof CronFields
): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  if (expression.includes(",")) {
    const values = expression
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (expression === "*") {
    return range(min, max);
  }

  if (expression.startsWith("*/")) {
    const step = parseInt(expression.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(
        `Invalid step value "${expression}" for field "${fieldName}"`
      );
    }
    return range(min, max).filter((v) => (v - min) % step === 0);
  }

  if (expression.includes("/")) {
    const [rangePart, stepPart] = expression.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(
        `Invalid step value "${expression}" for field "${fieldName}"`
      );
    }
    const base = parseField(rangePart, fieldName);
    return base.filter((v) => (v - base[0]) % step === 0);
  }

  if (expression.includes("-")) {
    const [startStr, endStr] = expression.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end) || start > end) {
      throw new Error(
        `Invalid range "${expression}" for field "${fieldName}"`
      );
    }
    if (start < min || end > max) {
      throw new Error(
        `Range "${expression}" out of bounds [${min}-${max}] for field "${fieldName}"`
      );
    }
    return range(start, end);
  }

  const value = parseInt(expression, 10);
  if (isNaN(value)) {
    throw new Error(
      `Invalid value "${expression}" for field "${fieldName}"`
    );
  }
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of bounds [${min}-${max}] for field "${fieldName}"`
    );
  }
  return [value];
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] =
    parts;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

export default parseCron;
export type { CronFields };

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

const isPlainObject = (val: unknown): val is PlainObject =>
  val !== null && typeof val === "object" && !Array.isArray(val) &&
  Object.getPrototypeOf(val) === Object.prototype;

const deepMerge = (target: unknown, source: unknown): unknown => {
  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };
    for (const key of Object.keys(source)) {
      result[key] = deepMerge(target[key], source[key]);
    }
    return result;
  }

  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  return source !== undefined ? source : target;
};

export default deepMerge;

type AnyFunction = (...args: unknown[]) => unknown;

type DebouncedFunction<T extends AnyFunction> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

function debounce<T extends AnyFunction>(fn: T, delay: number): DebouncedFunction<T> {
  let timerId: ReturnType<typeof setTimeout> | undefined;
  let pendingArgs: Parameters<T> | undefined;

  const invoke = () => {
    if (pendingArgs !== undefined) {
      const args = pendingArgs;
      pendingArgs = undefined;
      fn(...args);
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;

    if (timerId !== undefined) {
      clearTimeout(timerId);
    }

    timerId = setTimeout(() => {
      timerId = undefined;
      invoke();
    }, delay);
  };

  debounced.cancel = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    pendingArgs = undefined;
  };

  debounced.flush = (): void => {
    if (timerId !== undefined) {
      clearTimeout(timerId);
      timerId = undefined;
    }
    invoke();
  };

  return debounced;
}

export default debounce;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject | Primitive | Array<unknown>,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = "[]";
    } else {
      obj.forEach((item, index) => {
        flattenObject(
          item as NestedObject | Primitive | Array<unknown>,
          prefix ? `${prefix}.${index}` : `${index}`,
          result
        );
      });
    }
    return result;
  }

  const keys = Object.keys(obj);
  if (keys.length === 0) {
    if (prefix) result[prefix] = "{}";
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    flattenObject(
      (obj as NestedObject)[key] as NestedObject | Primitive | Array<unknown>,
      newKey,
      result
    );
  }

  return result;
}

export default flattenObject;

type CronObject = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronObject, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  const validateValue = (value: number, context: string): number => {
    if (!Number.isInteger(value) || value < min || value > max) {
      throw new RangeError(
        `Value ${value} out of range [${min}, ${max}] in "${context}"`
      );
    }
    return value;
  };

  const parseSingleToken = (token: string): number[] => {
    // Wildcard: *
    if (token === "*") {
      return range(min, max);
    }

    // Step: */n or start-end/n
    if (token.includes("/")) {
      const [rangePart, stepPart] = token.split("/");
      const step = parseInt(stepPart, 10);

      if (isNaN(step) || step < 1) {
        throw new Error(`Invalid step value in "${token}"`);
      }

      let start = min;
      let end = max;

      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [s, e] = rangePart.split("-").map(Number);
          start = validateValue(s, token);
          end = validateValue(e, token);
        } else {
          start = validateValue(parseInt(rangePart, 10), token);
        }
      }

      const values: number[] = [];
      for (let v = start; v <= end; v += step) {
        values.push(v);
      }
      return values;
    }

    // Range: start-end
    if (token.includes("-")) {
      const parts = token.split("-");
      if (parts.length !== 2) {
        throw new Error(`Invalid range in "${token}"`);
      }
      const [start, end] = parts.map(Number);
      validateValue(start, token);
      validateValue(end, token);

      if (start > end) {
        throw new RangeError(`Range start ${start} > end ${end} in "${token}"`);
      }
      return range(start, end);
    }

    // Single number
    const num = parseInt(token, 10);
    if (isNaN(num)) {
      throw new Error(`Invalid cron token "${token}"`);
    }
    return [validateValue(num, token)];
  };

  // Comma-separated list
  const tokens = field.split(",");
  const allValues = tokens.flatMap(parseSingleToken);

  // Deduplicate and sort
  return [...new Set(allValues)].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronObject => {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${fields.length} in "${expression}"`
    );
  }

  const result = {} as CronObject;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name = FIELD_NAMES[i];
    result[name] = parseField(fields[i], FIELD_CONFIGS[name]);
  }

  return result;
};

export default parseCron;

type DebouncedFunction<T extends (...args: Parameters<T>) => ReturnType<T>> = {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
};

export default function debounce<T extends (...args: Parameters<T>) => ReturnType<T>>(
  fn: T,
  delay: number
): DebouncedFunction<T> {
  let timer: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const invoke = () => {
    if (pendingArgs !== null) {
      fn(...pendingArgs);
      pendingArgs = null;
    }
  };

  const clear = () => {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
  };

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;
    clear();
    timer = setTimeout(() => {
      timer = null;
      invoke();
    }, delay);
  };

  debounced.cancel = () => {
    clear();
    pendingArgs = null;
  };

  debounced.flush = () => {
    clear();
    invoke();
  };

  return debounced;
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens"));

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = intervalsNeeded * this.refillIntervalMs;

        setTimeout(attempt, Math.max(delay, 1));
      };

      attempt();
    });
  }
}

export default RateLimiter;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

function isPlainObject(val: unknown): val is PlainObject {
  return (
    val !== null &&
    typeof val === "object" &&
    !Array.isArray(val) &&
    Object.getPrototypeOf(val) === Object.prototype
  );
}

export function deepMerge(target: unknown, source: unknown): unknown {
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };
    for (const key of Object.keys(source)) {
      result[key] = deepMerge(target[key], source[key]);
    }
    return result;
  }

  return source === undefined ? target : source;
}

export default deepMerge;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) throw new RangeError("tokens exceeds maxTokens");

    while (!this.tryConsume(tokens)) {
      this.refill();
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      Object.keys(val).length > 0
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else {
      result[fullKey] = Array.isArray(val) ? (val as unknown as Primitive) : (val as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type AnyFunction = (...args: unknown[]) => unknown;

interface Debounced<T extends AnyFunction> {
  (...args: Parameters<T>): void;
  cancel(): void;
  flush(): void;
}

function debounce<T extends AnyFunction>(fn: T, delay: number): Debounced<T> {
  let timer: ReturnType<typeof setTimeout> | null = null;
  let pendingArgs: Parameters<T> | null = null;

  const debounced = (...args: Parameters<T>): void => {
    pendingArgs = args;
    if (timer !== null) clearTimeout(timer);
    timer = setTimeout(() => {
      timer = null;
      const args = pendingArgs!;
      pendingArgs = null;
      fn(...args);
    }, delay);
  };

  debounced.cancel = (): void => {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
    }
    pendingArgs = null;
  };

  debounced.flush = (): void => {
    if (timer !== null) {
      clearTimeout(timer);
      timer = null;
      const args = pendingArgs!;
      pendingArgs = null;
      fn(...args);
    }
  };

  return debounced;
}

export default debounce;
